// ── Inputs ──────────────────────────────────────────────
const quote   = $node["Get Market Quote"].json;
const history = $node["Get Historical Data"].json;
const candles = history.candles || [];

if (candles.length < 30) {
  throw new Error("Not enough candle data: " + candles.length + " candles received");
}

// ── RSI (14) — Wilder method ─────────────────────────────
const last15 = candles.slice(-15);
let gains = 0, losses = 0;
for (let i = 1; i < last15.length; i++) {
  const diff = last15[i].close - last15[i - 1].close;
  if (diff > 0) gains += diff;
  else losses += Math.abs(diff);
}
const avgGain = gains / 14;
const avgLoss = losses / 14;
const rs  = avgLoss === 0 ? 100 : avgGain / avgLoss;
const rsi = Math.round(100 - (100 / (1 + rs)));

// ── EMA helper ───────────────────────────────────────────
function calcEMA(prices, period) {
  const k = 2 / (period + 1);
  let ema = prices[0];
  for (let i = 1; i < prices.length; i++) {
    ema = prices[i] * k + ema * (1 - k);
  }
  return Math.round(ema * 100) / 100;
}
const closes = candles.map(c => c.close);
const ema9  = calcEMA(closes.slice(-20), 9);
const ema21 = calcEMA(closes.slice(-30), 21);

// ── MACD (12, 26, 9) ─────────────────────────────────────
const ema12 = calcEMA(closes.slice(-30), 12);
const ema26 = calcEMA(closes.slice(-30), 26);
const macdLine = Math.round((ema12 - ema26) * 100) / 100;
const macdValues = [];
for (let i = closes.length - 9; i < closes.length; i++) {
  const e12 = calcEMA(closes.slice(0, i + 1).slice(-30), 12);
  const e26 = calcEMA(closes.slice(0, i + 1).slice(-30), 26);
  macdValues.push(e12 - e26);
}
const macdSignal    = Math.round(calcEMA(macdValues, 9) * 100) / 100;
const macdHistogram = Math.round((macdLine - macdSignal) * 100) / 100;

// ── MA20 & Volume ─────────────────────────────────────────
const last20 = closes.slice(-20);
const ma20   = Math.round(last20.reduce((a, b) => a + b, 0) / last20.length);
const volumes  = candles.slice(-10).map(c => c.volume);
const avgVol   = volumes.reduce((a, b) => a + b, 0) / volumes.length;
const lastVol  = candles[candles.length - 1].volume;
const volRatio = avgVol > 0 ? parseFloat((lastVol / avgVol).toFixed(2)) : 1;

const last20Candles = candles.slice(-20).map(c => ({
  timestamp: c.timestamp, open: c.open, high: c.high,
  low: c.low, close: c.close, volume: c.volume
}));

const nowIST = new Date().toLocaleString("en-IN", { timeZone: "Asia/Kolkata" });

return {
  json: {
    symbol: "NIFTY", timeframe: "15m", timestamp: nowIST,
    livePrice: quote.last_price, candles: last20Candles,
    indicators: {
      rsi, ema9, ema21, ma20,
      macd: { line: macdLine, signal: macdSignal, histogram: macdHistogram },
      volume_ratio: volRatio,
      trend: quote.last_price > ema21 ? "BULLISH" : "BEARISH"
    }
  }
};

const merged = $input.item.json || {};

let marketData = null;
if (merged && merged.indicators && merged.candles) {
  marketData = merged;
}
if (!marketData) {
  try { marketData = $node["Build Claude Payload"].json; } catch (e) { marketData = null; }
}
if (!marketData) {
  throw new Error("Market data unavailable: Build Claude Payload not executed");
}

let researchRaw = null;
if (merged && merged.researchBrief && merged.researchBrief.overallSentiment) {
  researchRaw = merged.researchBrief;
} else if (merged && merged.overallSentiment) {
  researchRaw = merged;
} else {
  try { researchRaw = $node["Run Research"].json; } catch (e) { researchRaw = null; }
}

const research = (researchRaw && researchRaw.overallSentiment)
  ? researchRaw
  : {
      overallSentiment: "NEUTRAL", sentimentScore: 0, confidence: 0,
      bullishSignals: 0, bearishSignals: 0, neutralSignals: 0,
      topHeadlines: [], redditConsensus: "NEUTRAL",
      nseAnnouncementFlag: false,
      sources: { newsCount: 0, redditCount: 0, nseCount: 0 },
      pastLessons: [],
      summary: "Research data unavailable. Decision based on technicals only."
    };

return {
  json: {
    symbol: marketData.symbol,
    timeframe: marketData.timeframe,
    timestamp: marketData.timestamp,
    livePrice: marketData.livePrice,
    candles: marketData.candles,
    indicators: marketData.indicators,
    researchBrief: {
      overallSentiment: research.overallSentiment,
      sentimentScore: research.sentimentScore,
      confidence: research.confidence,
      bullishSignals: research.bullishSignals,
      bearishSignals: research.bearishSignals,
      neutralSignals: research.neutralSignals,
      topHeadlines: research.topHeadlines,
      redditConsensus: research.redditConsensus,
      nseAnnouncementFlag: research.nseAnnouncementFlag,
      sources: research.sources,
      pastLessons: research.pastLessons || [],
      summary: research.summary
    }
  }
};

const choices = $input.item.json.choices;
if (!choices || !Array.isArray(choices) || choices.length === 0) {
  throw new Error("OpenRouter returned no choices: " + JSON.stringify($input.item.json));
}
const raw = choices[0]?.message?.content || "";
if (!raw) throw new Error("Claude message content is empty");
const cleaned = raw.replace(/```json|```/g, "").trim();
const match = cleaned.match(/\{[\s\S]*\}/);
if (!match) throw new Error("Claude did not return valid JSON. Raw: " + raw);
let parsed;
try { parsed = JSON.parse(match[0]); }
catch(e) { throw new Error("JSON parse failed: " + e.message + " | Raw: " + match[0]); }
const required = ["approved", "action", "entry_price", "target_price", "stop_loss", "quantity", "confidence", "risk_flag", "reasoning"];
for (const field of required) {
  if (parsed[field] === undefined) throw new Error("Missing field: '" + field + "'");
}
return { json: parsed };

