      "Stock: *" + ind.symbol + "*\n" +
      "Decision: *" + g.action + "*\n" +
      "Entry:     ₹" + g.entry_price + "\n" +
      "Target:    ₹" + g.target_price + "\n" +
      "Stop Loss: ₹" + g.stop_loss + "\n" +
      "Qty:       " + g.quantity + "\n\n" +
      "📊 *Technicals*\n" +
      "RSI: " + ind.indicators.rsi + "  |  Trend: " + ind.indicators.trend + "\n" +
      "EMA9: " + ind.indicators.ema9 + "  EMA21: " + ind.indicators.ema21 + "\n" +
      "MACD: " + ind.indicators.macd.line + " / Signal: " + ind.indicators.macd.signal + "\n\n" +
      "📰 *Sentiment*\n" +
