const candles = history.candles || [];

if (candles.length < 30) {
  throw new Error("Not enough candle data: " + candles.length + " candles received");
}

// ── RSI (14) — Wilder method ─────────────────────────────
const last15 = candles.slice(-15);
let gains = 0, losses = 0;
for (let i = 1; i < last15.length; i++) {
  const diff = last15[i].close - last15[i - 1].close;
  if (diff > 0) gains += diff;
  else losses += Math.abs(diff);
}
const avgGain = gains / 14;
const avgLoss = losses / 14;
const rs  = avgLoss === 0 ? 100 : avgGain / avgLoss;
const rsi = Math.round(100 - (100 / (1 + rs)));

// ── EMA helper ───────────────────────────────────────────
function calcEMA(prices, period) {
  const k = 2 / (period + 1);
  let ema = prices[0];
  for (let i = 1; i < prices.length; i++) {
    ema = prices[i] * k + ema * (1 - k);
  }
  return Math.round(ema * 100) / 100;
}
const closes = candles.map(c => c.close);
const ema9  = calcEMA(closes.slice(-20), 9);
const ema21 = calcEMA(closes.slice(-30), 21);

// ── MACD (12, 26, 9) ─────────────────────────────────────
const ema12 = calcEMA(closes.slice(-30), 12);
const ema26 = calcEMA(closes.slice(-30), 26);
const macdLine = Math.round((ema12 - ema26) * 100) / 100;
const macdValues = [];
for (let i = closes.length - 9; i < closes.length; i++) {
  const e12 = calcEMA(closes.slice(0, i + 1).slice(-30), 12);
  const e26 = calcEMA(closes.slice(0, i + 1).slice(-30), 26);
  macdValues.push(e12 - e26);
}
const macdSignal    = Math.round(calcEMA(macdValues, 9) * 100) / 100;
const macdHistogram = Math.round((macdLine - macdSignal) * 100) / 100;

